 52	import './protected-apps.scss';
 53	import {
 54	  EnrollApplicationTypes,
 55	  getAlertMessages,
 56	  getEnrollDropdownItems,
 57	  SyncStatusInfo,
 58	} from './utils';
 59	
 60	type SelectExpandableProps = {
 61	  title: React.ReactNode;
 62	  tooltipContent: string;
 63	  onSelect: (
 64	    event: React.MouseEvent<HTMLElement, MouseEvent>,
 65	    buttonRef: React.MutableRefObject<HTMLElement>
 66	  ) => void;
 67	  buttonId: ExpandableComponentType;
 68	  className?: string;
 69	};
 70	
 71	const EnrollApplicationNoDataButton: React.FC = () => (
 72	  <EnrollApplicationButton isNoDataMessage />
 73	);
 74	
 75	const ManagedApplicationsModalLazy = React.lazy(
 76	  () => import('../modals/protected-applications/managed-applications-modal')
 77	);
 78	
 79	export const EnrollApplicationButton: React.FC<{
 80	  isNoDataMessage?: boolean;
 81	  toggleVariant?: ToggleVariant;
 82	}> = ({ isNoDataMessage, toggleVariant }) => {
 83	  const { t } = useCustomTranslation();
 84	  const navigate = useNavigate();
 85	  const launcher = useModal();
 86	
 87	  return (
 88	    <div
 89	      className={classNames({
 90	        'pf-v6-u-display-flex pf-v6-u-flex-direction-column pf-v6-u-flex-direction-row-on-lg mco-protected-applications__popover':
 91	          !isNoDataMessage,
 92	      })}
 93	    >
 94	      <div className="pf-v6-u-ml-md pf-v6-u-mt-md">
 95	        <ActionDropdown
 96	          id="enroll-application-types"
 97	          aria-label={t('Enroll application')}
 98	          text={t('Enroll application')}
 99	          toggleVariant={toggleVariant || 'primary'}
100	          onSelect={(id: EnrollApplicationTypes) => {
101	            id === EnrollApplicationTypes.DISCOVERED &&
102	              navigate(
103	                `${DR_BASE_ROUTE}/protected-applications/${referenceForModel(
104	                  DRPlacementControlModel
105	                )}/~new`
106	              );
107	            id === EnrollApplicationTypes.MANAGED &&
108	              launcher(ManagedApplicationsModalLazy, { isOpen: true });
109	          }}
110	          dropdownItems={getEnrollDropdownItems(t)}
111	        />
112	      </div>
113	      <PopoverStatus
114	        statusBody={
115	          <div
116	            className={classNames({
117	              'pf-v6-u-ml-md': true,
118	              'pf-v6-u-mt-md': isNoDataMessage,
119	            })}
120	          >
121	            <OutlinedQuestionCircleIcon className="pf-v6-u-mr-sm" />
122	            {t('Application types and their enrollment processes')}
123	          </div>
124	        }
125	        title={t('Application types and their enrollment processes')}
126	        popoverPosition={PopoverPosition.bottom}
127	      >
128	        <Trans t={t}>
129	          <p className="co-break-word pf-v6-u-font-weight-bold">
130	            ACM discovered applications:
131	          </p>
132	          <p className="co-break-word pf-v6-u-mb-sm">
133	            Based on modular and microservices architecture, uses operators for
134	            dynamically created kubernetes objects. Eg:{' '}
135	            <span className="pf-v6-u-font-weight-bold">
136	              CloudPak, Custom-created applications
137	            </span>
138	          </p>
139	          <p className="co-break-word pf-v6-u-mb-md">
140	            <span className="pf-v6-u-font-weight-bold">
141	              Enrollment process:
142	            </span>{' '}
143	            Discovered applications are enrolled under disaster recovery through
144	            enabling protection for their namespaces and further defining the
145	            scope of this protection within namespace through recipe selection
146	            or resource label.
147	          </p>
148	
149	          <p className="co-break-word pf-v6-u-font-weight-bold">
150	            ACM managed applications:
151	          </p>
152	          <p className="co-break-word pf-v6-u-mb-sm">
153	            Based on subscribing to one or more Kubernetes resource repositories
154	            (channel resource) that contains resources that are deployed on
155	            managed clusters. Eg:{' '}
156	            <span className="pf-v6-u-font-weight-bold">
157	              ApplicationSet, Subscriptions
158	            </span>
159	          </p>
160	          <p className="co-break-word">
161	            <span className="pf-v6-u-font-weight-bold">
162	              Enrollment process:
163	            </span>{' '}
164	            Individually protect managed application with flexibility for
165	            distinct configurations for different sub-categories of managed
166	            application based on specific requirements.
167	          </p>
168	        </Trans>
169	      </PopoverStatus>
170	    </div>
171	  );
172	};
173	
174	export const EmptyRowMessage: React.FC = () => {
175	  const { t } = useCustomTranslation();
176	  return (
177	    <Bullseye className="pf-v6-u-mt-xl">
178	      {t('No protected applications found')}
179	    </Bullseye>
180	  );
181	};
182	
183	export const NoDataMessage: React.FC = () => {
184	  const { t } = useCustomTranslation();
185	  return (
186	    <EmptyPage
187	      title={t('Looks like there are no applications here.')}
188	      ButtonComponent={EnrollApplicationNoDataButton}
189	      isLoaded
190	      canAccess
191	    >
192	      <Trans t={t}>
193	        <p>
194	          You do not have any <strong>discovered applications</strong> that are
195	          protected yet. For details about your{' '}
196	          <strong>protected managed applications</strong>, navigate to the{' '}
197	          <strong>Applications</strong> page, as this information is not
198	          maintained here.
199	        </p>
200	        <br />
201	        <p>
202	          Click <strong>Enroll applications</strong> to add disaster recovery
203	          protection to your applications.
204	        </p>
205	      </Trans>
206	    </EmptyPage>
207	  );
208	};
209	
210	export const AlertMessages: React.FC = () => {
211	  const { t } = useCustomTranslation();
212	
213	  const navigate = useNavigate();
214	  const location = useLocation();
215	  const params = new URLSearchParams(location.search);
216	  const recentlyEnrolledApp = params.get(ENROLLED_APP_QUERY_PARAMS_KEY) ?? '';
217	  const relocatedApp = params.get(RELOCATED_APP_QUERY_PARAM) ?? '';
218	  const relocatedCluster = params.get(RELOCATED_CLUSTER_QUERY_PARAM) ?? '';
219	  const failedOverApp = params.get(FAILED_OVER_APP_QUERY_PARAM) ?? '';
220	  const failedOverCluster = params.get(FAILED_OVER_CLUSTER_QUERY_PARAM) ?? '';
221	
222	  const messages: AlertProps[] = getAlertMessages(
223	    t,
224	    recentlyEnrolledApp,
225	    navigate,
226	    relocatedApp,
227	    relocatedCluster,
228	    failedOverApp,
229	    failedOverCluster
230	  );
231	
232	  return (
233	    <>
234	      {messages.map((message) => (
235	        <Alert
236	          variant={message.variant}
237	          title={message.title}
238	          key={message.key}
239	          className="pf-v6-u-mt-xs pf-v6-u-mb-xs"
240	          {...(message?.isInline ? { isInline: message.isInline } : {})}
241	          {...(message?.actionClose
242	            ? { actionClose: message.actionClose }
243	            : {})}
244	        >
245	          {message.children}
246	        </Alert>
247	      ))}
248	    </>
249	  );
250	};
251	
252	export const SelectExpandable: React.FC<SelectExpandableProps> = ({
253	  title,
254	  tooltipContent,
255	  onSelect,
256	  buttonId,
257	  className,
258	}) => {
259	  const buttonRef = React.useRef<HTMLElement>();
260	  return (
261	    <Tooltip content={tooltipContent}>
262	      <Button
263	        ref={buttonRef}
264	        variant={ButtonVariant.link}
265	        onClick={(event) => onSelect(event, buttonRef)}
266	        id={buttonId}
267	        className={className}
268	        isInline
269	      >
270	        {title}
271	      </Button>
272	    </Tooltip>
273	  );
274	};
275	
276	export enum ExpandableComponentType {
277	  DEFAULT = '',
278	  NS = 'namespaces',
279	}
280	
281	export type SyncStatus = { [appName: string]: SyncStatusInfo };
282	
283	export type ExpandableComponentProps = {
284	  view?: ProtectedApplicationViewKind;
285	  syncStatusInfo?: SyncStatusInfo;
286	  mcvName?: string;
287	};
288	
289	export const NamespacesDetails: React.FC<ExpandableComponentProps> = ({
290	  view,
291	  mcvName,
292	}) => {
293	  const { t } = useCustomTranslation();
294	
295	  const applicationType = view?.status?.applicationInfo?.type;
296	  const isDiscovered = applicationType === 'Discovered';
297	  const clusterName = view ? getPrimaryCluster(view) : '';
298	  const destinationNamespace =
299	    !isDiscovered && view?.status?.applicationInfo?.destinationNamespace;
300	  const enrolledNamespaces = view?.status?.drInfo?.protectedNamespaces || [];
301	  const namespaces = isDiscovered
302	    ? enrolledNamespaces
303	    : destinationNamespace
304	      ? [destinationNamespace]
305	      : [];
306	
307	  const mcvResources: Record<string, WatchK8sResource> = {};
308	  if (clusterName && mcvName) {
309	    mcvResources[mcvName] = buildMCVResource(clusterName, mcvName);
310	  }
311	  const mcvs = useK8sWatchResources(mcvResources);
312	  const {
313	    loaded,
314	    loadError,
315	    data: consistencyGroups,
316	  } = extractConsistencyGroups(mcvs);
317	
318	  const consistencyGroupsCount = consistencyGroups?.reduce((acc, group) => {
319	    const namespace = group.namespace;
320	    acc[namespace] = acc[namespace] ? acc[namespace] + 1 : 1;
321	    return acc;
322	  }, {});
323	
324	  const [selectedNamespace, setSelectedNamespace] = React.useState<
325	    string | null
326	  >(null);
327	  const openModal = (namespace: string) => {
328	    setSelectedNamespace(namespace);
329	  };
330	
331	  const closeModal = () => {
332	    setSelectedNamespace(null);
333	  };
334	
335	  if (!view) {
336	    return <DataUnavailableError className="pf-v6-u-pt-xl pf-v6-u-pb-xl" />;
337	  }
338	
339	  const hasData = applicationType && namespaces.length > 0;
340	
341	  if (!hasData) {
342	    return <DataUnavailableError className="pf-v6-u-pt-xl pf-v6-u-pb-xl" />;
343	  }
344	
345	  const applicationName = getName(view);
346	  const applicationNamespace = getNamespace(view);
347	
348	  const description = (
349	    <Trans t={t}>
350	      <strong>Application:</strong> {applicationName} (Namespace:{' '}
351	      {applicationNamespace})
352	    </Trans>
353	  );
354	
355	  return (
356	    <>
357	      <Grid hasGutter>
358	        <GridItem span={3} className="pf-v6-u-text-align-center">
359	          <Text component="h6" className="pf-v6-u-font-weight-bold">
360	            {t('Application type')}
361	          </Text>
362	        </GridItem>
363	        <GridItem span={6} className="pf-v6-u-text-align-center">
364	          <Text component="h6" className="pf-v6-u-font-weight-bold">
365	            {isDiscovered
366	              ? t('Protected namespaces')
367	              : t('Destination namespace')}
368	          </Text>
369	        </GridItem>
370	        <GridItem span={3} className="pf-v6-u-text-align-center">
371	          <Text component="h6" className="pf-v6-u-font-weight-bold">
372	            {t('Volume Consistency groups')}
373	          </Text>
374	        </GridItem>
375	
376	        <GridItem span={3} className="pf-v6-u-text-align-center">
377	          <Text>{applicationType}</Text>
378	        </GridItem>
379	        <GridItem
380	          span={6}
381	          className="pf-v6-u-text-align-center pf-v6-u-mx-auto"
382	        >
383	          {namespaces.map((namespace: string) => (
384	            <div key={namespace} className="pf-v6-u-mb-sm">
385	              <ResourceNameWIcon
386	                resourceModel={NamespaceModel}
387	                resourceName={namespace}
388	              />
389	            </div>
390	          ))}
391	        </GridItem>
392	        <GridItem span={3} className="pf-v6-u-text-align-center">
393	          {namespaces.map((namespace: string) => (
394	            <div key={namespace} className="pf-v6-u-mb-sm">
395	              {consistencyGroupsCount?.[namespace] ? (
396	                <Button
397	                  variant={ButtonVariant.link}
398	                  aria-label={t(`View details for ${namespace}`, {
399	                    namespace,
400	                  })}
401	                  onClick={() => openModal(namespace)}
402	                  isInline
403	                >
404	                  {consistencyGroupsCount[namespace]}
405	                </Button>
406	              ) : (
407	                <Text className="pf-v5-u-color-200">-</Text>
408	              )}
409	            </div>
410	          ))}
411	        </GridItem>
412	      </Grid>
413	
414	      {selectedNamespace && (
415	        <ConsistencyGroupsModal
416	          isOpen={!!selectedNamespace}
417	          description={description}
418	          onClose={closeModal}
419	          consistencyGroups={consistencyGroups.filter(
420	            (group) => group.namespace === selectedNamespace
421	          )}
422	          loaded={loaded}
423	          loadError={loadError}
424	        />
425	      )}
426	    </>
427	  );
428	};
429	
430	type ConsistencyGroupsModalProps = {
431	  isOpen: boolean;
432	  description: React.ReactNode;
433	  onClose: () => void;
434	  consistencyGroups: ConsistencyGroupInfo[];
435	  loaded: boolean;
436	  loadError: any;
437	};
438	
439	const ConsistencyGroupsModal: React.FC<ConsistencyGroupsModalProps> = ({
440	  isOpen,
441	  description,
442	  onClose,
443	  consistencyGroups,
444	  loaded,
445	  loadError,
446	}) => {
447	  const { t } = useCustomTranslation();
448	
449	  return (
450	    <Modal
451	      variant={ModalVariant.medium}
452	      title={t('Volume consistency groups')}
453	      description={description}
454	      isOpen={isOpen}
455	      onClose={onClose}
456	      aria-label={t('Volume consistency groups modal')}
457	    >
458	      <ConsistencyGroupsContent
459	        consistencyGroups={consistencyGroups}
460	        loaded={loaded}
461	        loadError={loadError}
462	      />
463	    </Modal>
464	  );
465	};

