300	  const destinationNamespace =
301	    !isDiscovered && view?.status?.applicationInfo?.destinationNamespace;
302	  const enrolledNamespaces = view?.status?.drInfo?.protectedNamespaces || [];
303	  const namespaces = isDiscovered
304	    ? enrolledNamespaces
305	    : destinationNamespace
306	      ? [destinationNamespace]
307	      : [];
308	
309	  const mcvResources: Record<string, WatchK8sResource> = {};
310	  if (clusterName && mcvName) {
311	    mcvResources[mcvName] = buildMCVResource(clusterName, mcvName);
312	  }
313	  const mcvs = useK8sWatchResources(mcvResources);
314	  const {
315	    loaded,
316	    loadError,
317	    data: consistencyGroups,
318	  } = extractConsistencyGroups(mcvs);
319	
320	  const consistencyGroupsCount = consistencyGroups?.reduce((acc, group) => {
321	    const namespace = group.namespace;
322	    acc[namespace] = acc[namespace] ? acc[namespace] + 1 : 1;
323	    return acc;
324	  }, {});
325	
326	  const [selectedNamespace, setSelectedNamespace] = React.useState<
327	    string | null
328	  >(null);
