347	  const applicationName = getName(view);
348	  const applicationNamespace = getNamespace(view);
349	
350	  const description = (
351	    <Trans t={t}>
352	      <strong>Application:</strong> {applicationName} (Namespace:{' '}
353	      {applicationNamespace})
354	    </Trans>
355	  );
356	
357	  return (
358	    <>
