360	        <GridItem span={3} className="pf-v6-u-text-align-center">
361	          <Content component="h6" className="pf-v6-u-font-weight-bold">
362	            {t('Application type')}
363	          </Content>
364	        </GridItem>
365	        <GridItem span={6} className="pf-v6-u-text-align-center">
366	          <Content component="h6" className="pf-v6-u-font-weight-bold">
367	            {isDiscovered
368	              ? t('Protected namespaces')
369	              : t('Destination namespace')}
370	          </Content>
371	        </GridItem>
372	        <GridItem span={3} className="pf-v6-u-text-align-center">
373	          <Content component="h6" className="pf-v6-u-font-weight-bold">
374	            {t('Volume Consistency groups')}
375	          </Content>
376	        </GridItem>
377	
378	        <GridItem span={3} className="pf-v6-u-text-align-center">
379	          <Content>{applicationType}</Content>
380	        </GridItem>
381	        <GridItem
382	          span={6}
383	          className="pf-v6-u-text-align-center pf-v6-u-mx-auto"
384	        >
385	          {namespaces.map((namespace: string) => (
386	            <div key={namespace} className="pf-v6-u-mb-sm">
387	              <ResourceNameWIcon
388	                resourceModel={NamespaceModel}
389	                resourceName={namespace}
390	              />
391	            </div>
392	          ))}
393	        </GridItem>
394	        <GridItem span={3} className="pf-v6-u-text-align-center">
395	          {namespaces.map((namespace: string) => (
396	            <div key={namespace} className="pf-v6-u-mb-sm">
397	              {consistencyGroupsCount?.[namespace] ? (
398	                <Button
399	                  variant={ButtonVariant.link}
400	                  aria-label={t(`View details for ${namespace}`, {
401	                    namespace,
402	                  })}
403	                  onClick={() => openModal(namespace)}
404	                  isInline
405	                >
406	                  {consistencyGroupsCount[namespace]}
407	                </Button>
408	              ) : (
409	                <Content style={{ color: 'var(--pf-t--global--text--color--subtle)' }}>-</Content>
410	              )}
411	            </div>
412	          ))}
